import usocket as socket
import ussl as ssl
import ujson as json
from machine import Pin
import time

led = Pin(2, Pin.OUT)

def handle_client(ws):
    while True:
        msg = ws.recv()
        if msg:
            try:
                data = json.loads(msg)
                if data['action'] == 'turn_on':
                    led.on()
                    ws.send(json.dumps({"status": "LED turned on"}))
                elif data['action'] == 'turn_off':
                    led.off()
                    ws.send(json.dumps({"status": "LED turned off"}))
            except Exception as e:
                ws.send(json.dumps({"error": str(e)}))

def websocket_server():
    addr = socket.getaddrinfo('0.0.0.0', 80)[0]
    s = socket.socket()
    s.bind(addr)
    s.listen(1)
    
    while True:
        cl, addr = s.accept()
        print('Client connected from', addr)
        ws = socket.socket()
        ws.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        ws.bind(addr)
        ws.listen(1)
        client, _ = ws.accept()
        
        try:
            handle_client(client)
        finally:
            client.close()

websocket_server()